17	#include <stdio.h>
18	#include <string.h>
19	#include <ctype.h>
20	#include "__stdio_internal.h"
21	
22	#define FLAG_IS_SET(x)	\
23		((flags & (1 << (strchr(kFlagCharacters, x) - kFlagCharacters))) != 0)
24	
25	#define SET_FLAG(x)	\
26		flags |= 1 << (strchr(kFlagCharacters, x) - kFlagCharacters)
27	
28	#define PREFIX_IS_SET(x)	\
29		((prefixes & (1 << (strchr(kPrefixCharacters, x) - kPrefixCharacters))) != 0)
30	
31	#define SET_PREFIX(x) \
32		prefixes |= 1 << (strchr(kPrefixCharacters, x) - kPrefixCharacters)
33	
34	#define MIN(x, y) ((x) < (y) ? (x) : (y))
35	#define MAX(x, y) ((x) > (y) ? (x) : (y))
36	
37	static const char *kHexDigits = "0123456789abcdef";
38	static const char *kFlagCharacters = "-+ 0";
39	static const char *kPrefixCharacters = "FNhlLzt";
40	
41	/*
42	 *	 % flags width .precision prefix format
43	 */
44	int vfprintf(FILE *f, const char *format, va_list args)
45	{
46	    int flags = 0;
47	    int prefixes = 0;
48	    int width = 0;
49	    int precision = 0;
50	
51	    enum {
52	        kScanText,
53	        kScanFlags,
54	        kScanWidth,
55	        kScanPrecision,
56	        kScanPrefix,
57	        kScanFormat
58	    } state = kScanText;
59	
60	    while (*format) {
61	        switch (state) {
62	            case kScanText:
63	                if (*format == '%') {
64	                    format++;
65	                    state = kScanFlags;
66	                    flags = 0;				/* reset attributes */
67	                    prefixes = 0;
68	                    width = 0;
69	                    precision = 0;
70	                } else
71	                    fputc(*format++, f);
72	
73	                break;
74	
75	            case kScanFlags: {
76	                const char *c;
77	
78	                if (*format == '%') {
79	                    fputc(*format++, f);
80	                    state = kScanText;
81	                    break;
82	                }
83	
84	                c = strchr(kFlagCharacters, *format);
85	                if (c) {
86	                    SET_FLAG(*format);
87	                    format++;
88	                } else
89	                    state = kScanWidth;
90	
91	                break;
92	            }
93	
94	            case kScanWidth:
95	                if (isdigit(*format))
96	                    width = width * 10 + *format++ - '0';
97	                else if (*format == '.') {
98	                    state = kScanPrecision;
99	                    format++;
100	                } else
101	                    state = kScanPrefix;
102	
103	                break;
104	
105	            case kScanPrecision:
106	                if (isdigit(*format))
107	                    precision = precision * 10 + *format++ - '0';
108	                else
109	                    state = kScanPrefix;
110	
111	                break;
112	
113	            case kScanPrefix: {
114	                const char *c = strchr(kPrefixCharacters, *format);
115	                if (c) {
116	                    SET_PREFIX(*format);
117	                    format++;
118	                } else
119	                    state = kScanFormat;
120	
121	                break;
122	            }
123	
124	            case kScanFormat: {
125	                char temp_string[64];
126	                int index;
127	                char pad_char;
128	                int pad_count;
129	                int radix = 10;
130	
131	                switch (*format) {
132	                    case 'p':	/* pointer */
133	                        width = 8;
134	                        SET_FLAG('0');
135	
136	                    /* falls through */
137	
138	                    case 'x':
139	                    case 'X':	/* unsigned hex */
140	                    case 'o':	/* octal */
141	                    case 'u':	/* Unsigned decimal */
142	                    case 'd':
143	                    case 'i':	{ /* Signed decimal */
144	                        unsigned long long value;
145	                        /* figure out base */
146	                        if (*format == 'o')
147	                            radix = 8;
148	                        else if (*format == 'x' || *format == 'X' || *format == 'p')
149	                            radix = 16;
150	                        else
151	                            radix = 10;
152	
153	                        if (PREFIX_IS_SET('L')) {
154	                            value = (unsigned long long int) va_arg(args, long long);
155	                        } else {
156	                            if ((*format == 'd' || *format == 'i'))
157	                                value = (unsigned long long int)(long long int) va_arg(args, int);
158	                            else
159	                                value = (unsigned long long int) va_arg(args, unsigned int);
160	                        }
161	
162	                        /* handle sign */
163	                        if ((*format == 'd' || *format == 'i')) {
164	                            if ((long long int) value < 0) {
165	                                value = (unsigned long long) (-(long long int) value);
166	                                fputc('-', f);
167	                            }
168	                        }
169	
170	                        /* write out the string backwards */
171	                        index = 63;
172	                        for (;;) {
173	                            temp_string[index] = kHexDigits[value % radix];
174	                            value /= radix;
175	                            if (value == 0)
176	                                break;
177	
178	                            if (index == 0)
179	                                break;
180	
181	                            index--;
182	                        }
183	
184	                        /* figure out width pad char */
185	                        if (FLAG_IS_SET('0'))
186	                            pad_char = '0';
187	                        else
188	                            pad_char = ' ';
189	
190	                        /* write width padding */
191	                        for (pad_count = (64 - index); pad_count < width; pad_count++)
192	                            fputc(pad_char, f);
193	
194	                        /* write precision padding */
195	                        for (; pad_count < precision; pad_count++)
196	                            fputc('0', f);
197	
198	                        /* write the string */
199	                        while (index < 64)
200	                            fputc(temp_string[index++], f);
201	
202	                        break;
203	                    }
204	
205	
206	                    case 'c':	/* Single character */
207	                        fputc(va_arg(args, int), f);
208	                        break;
209	
210	                    case 's': {	/* string */
211	                        int max_width;
212	                        char *c = va_arg(args, char*);
213	
214	                        if (precision == 0)
215	                            max_width = 0x7fffffff;
216	                        else
217	                            max_width = precision;
218	
219	                        for (index = 0; index < max_width && *c; index++)
220	                            fputc(*c++, f);
221	
222	                        while (index < MIN(width, max_width)) {
223	                            fputc(' ', f);
224	                            index++;
225	                        }
226	
227	                        break;
228	                    }
229	
230	                    case 'f':
231	                    case 'g':
232	                    {
233	                        // Printing floating point numbers accurately is a tricky problem.
234	                        // This implementation is simple and buggy.
235	                        // See "How to Print Floating Point Numbers Accurately" by Guy L. Steele Jr.
236	                        // and Jon L. White for the gory details.
237	                        // XXX does not handle inf and NaN
238	                        double floatval = va_arg(args, double);
239	                        int wholePart;
240	                        float frac;
241	
242	                        if (floatval < 0.0f)
243	                        {
244	                            fputc('-', f);
245	                            floatval = -floatval;
246	                        }
247	
248	                        wholePart = (int) floatval;
249	                        frac = floatval - wholePart;
250	
251	                        // Print the whole part (XXX ignores padding)
252	                        if (wholePart == 0)
253	                            fputc('0', f);
254	                        else
255	                        {
256	                            char wholeStr[20];
257	                            unsigned int wholeOffs = sizeof(wholeStr);
258	                            while (wholePart > 0)
259	                            {
260	                                int digit = wholePart % 10;
261	                                wholeStr[--wholeOffs] = digit + '0';
262	                                wholePart /= 10;
263	                            }
264	
265	                            while (wholeOffs < sizeof(wholeStr))
266	                                fputc(wholeStr[wholeOffs++], f);
267	                        }
268	
269	                        fputc('.', f);
270	
271	                        // Print the fractional part, not especially accurately
272	                        int maxDigits = precision > 0 ? precision : 7;
